module register_with_async_reset(
    input               obf_clk,
    input               rst,
    input   [31:0]      data_in,

    output reg [31:0]   data_out
);

always@(posedge obf_clk or posedge rst) begin
    if (rst)
        data_out <= 32'b00000000000000000000000000000000;
    else
        data_out <= data_in;
end

endmodule
